  constructor(ctrl: AppController) {
    this.ctrl = ctrl;
    this.selectedDate = new Date().toISOString().slice(0, 10);
  }

  prevMonth(): void {
    this.displayMonth = new Date(this.displayMonth.getFullYear(), this.displayMonth.getMonth() - 1, 1);
