  private ctrl: AppController;
  selectedCourseId: string = '';
  selectedDate: string = '';
  selectedTime: string = '';
  selectedMemberId: string = '';
  error: string = '';

  constructor(ctrl: AppController) {
    this.ctrl = ctrl;
    this.selectedDate = new Date().toISOString().slice(0, 10);
  }

  async submit(): Promise<LessonBooking | string | null> {
    this.error = '';
    if (!this.selectedCourseId || !this.selectedDate || !this.selectedTime || !this.selectedMemberId) {
      this.error = '请完善预约信息';
      return null;
