80	export class AppStore {
81	  private rdb: relationalStore.RdbStore | null = null;
82	
83	  async init(context: Context): Promise<void> {
84	    if (this.rdb) return;
85	    const config: relationalStore.StoreConfig = {
86	      name: DB_NAME,
87	      securityLevel: relationalStore.SecurityLevel.S1,
88	    };
89	    this.rdb = await relationalStore.getRdbStore(context, config);
90	    await this.execSchema();
