93	  private async execSchema(): Promise<void> {
94	    if (!this.rdb) return;
95	    const statements = SCHEMA.split(';').map(s => s.trim()).filter(Boolean);
96	    for (const stmt of statements) {
97	      await this.rdb.executeSql(stmt);
