import { AppController } from '../viewmodel/AppState';
import { Theme } from '../common/Theme';
import { Member } from '../models/Models';
import { DateUtil } from '../utils/AppUtils';

@Component
export struct HomePage {
  @ObjectLink ctrl: AppController;
  onPoints: () => void = () => {};
  onBooking: () => void = () => {};
  onDormant: () => void = () => {};
  onInventory: () => void = () => {};

  build() {
    Column({ space: 16 }) {
      // Header
      Stack({ alignContent: Alignment.Center }) {
        Column()
          .width('100%')
          .height(56)
          .linearGradient({
            angle: 180,
            direction: GradientDirection.Bottom,
            colors: [[Theme.headerGradientStart, 0.0], [Theme.headerGradientEnd, 1.0]]
          })
          .borderRadius({ bottomLeft: 28, bottomRight: 28 })

        Text('手作·印记')
          .id('home-header-title')
          .fontSize(18)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textOnBrand)
      }
      .width('100%')
      .height(56)

      Scroll() {
        Column({ space: 16 }) {
          // Check-in card
          Row() {
            Column({ space: 6 }) {
              Text('今日到店')
                .fontSize(20)
                .fontWeight(FontWeight.Bold)
                .fontColor(Theme.textOnBrand)
              Text('签到即可 +5 积分，记录你的手作时光')
                .fontSize(13)
                .fontColor(Theme.textOnBrand)
                .opacity(0.92)
            }
            .alignItems(HorizontalAlign.Start)

            Button('签到', { type: ButtonType.Normal })
              .id('home-checkin-button')
              .height(48)
              .borderRadius(Theme.radiusButton)
              .backgroundColor(Theme.cardBg)
              .fontColor(Theme.brandPrimary)
              .fontSize(16)
              .fontWeight(FontWeight.Bold)
              .padding({ left: 24, right: 24 })
              .onClick(() => this.ctrl.checkinCurrent())
          }
          .width('100%')
          .height(96)
          .padding(20)
          .borderRadius(Theme.radiusCard)
          .linearGradient({
            angle: 135,
            direction: GradientDirection.RightTop,
            colors: [[Theme.brandPrimary, 0.0], [Theme.brandDark, 1.0]]
          })
          .justifyContent(FlexAlign.SpaceBetween)
          .alignItems(VerticalAlign.Center)

          // Points card
          Row() {
            Column({ space: 4 }) {
              Text('当前积分')
                .fontSize(13)
                .fontColor(Theme.textSecondary)
              Text(`${this.currentPoints()}`)
                .id('points-balance')
                .fontSize(36)
                .fontWeight(FontWeight.Bold)
                .fontColor(Theme.brandPrimary)
            }
            .alignItems(HorizontalAlign.Start)

            Column()
              .id('home-points-detail-link')
              .width(40)
              .height(40)
              .borderRadius(Theme.radiusSmall)
              .backgroundColor(Theme.brandSoft)
              .onClick(() => this.onPoints())
          }
          .id('home-points-card')
          .width('100%')
          .padding(20)
          .borderRadius(Theme.radiusCard)
          .backgroundColor(Theme.cardBg)
          .justifyContent(FlexAlign.SpaceBetween)
          .alignItems(VerticalAlign.Center)

          // Upcoming lesson card
          Column({ space: 12 }) {
            Row({ space: 8 }) {
              CalendarIcon({ size: 20, color: Theme.brandPrimary })
              Text('待上课程')
                .fontSize(18)
                .fontWeight(FontWeight.Bold)
                .fontColor(Theme.textPrimary)
            }
            .width('100%')

            this.LessonRow()

            Button('预约课程', { type: ButtonType.Normal })
              .id('home-book-lesson-button')
              .height(40)
              .borderRadius(Theme.radiusSmall)
              .backgroundColor(Theme.brandLight)
              .fontColor(Theme.textOnBrand)
              .fontSize(14)
              .fontWeight(FontWeight.Bold)
              .padding({ left: 18, right: 18 })
              .onClick(() => this.onBooking())
          }
          .id('home-upcoming-lesson-card')
          .width('100%')
          .padding(20)
          .borderRadius(Theme.radiusCard)
          .backgroundColor(Theme.cardBg)
          .alignItems(HorizontalAlign.Start)

          // Menu list
          Column({ space: 12 }) {
            MenuRow({
              id: 'home-dormant-link',
              title: '沉睡提醒',
              badge: `${this.ctrl.state.dormantMembers().length}`,
              onClick: () => this.onDormant(),
              iconColor: Theme.alert,
            })
            MenuRow({
              id: 'home-inventory-link',
              title: '库存管理',
              badge: '',
              onClick: () => this.onInventory(),
              iconColor: Theme.success,
            })
          }
          .width('100%')

          // Empty state
          if (this.isEmpty()) {
            Column({ space: 12 }) {
              Text('还没有记录')
                .id('home-empty-state')
                .fontSize(16)
                .fontWeight(FontWeight.Bold)
                .fontColor(Theme.textPrimary)
              Text('签到或预约第一节课程，开启你的手作之旅')
                .fontSize(13)
                .fontColor(Theme.textSecondary)
            }
            .width('100%')
            .padding(32)
            .borderRadius(Theme.radiusCard)
            .backgroundColor(Theme.cardBg)
          }
        }
        .width('100%')
        .padding(Theme.pageHorizontalPadding)
        .constraintSize({ maxWidth: Theme.contentMaxWidth })
      }
      .width('100%')
      .layoutWeight(1)
      .scrollBar(BarState.Off)
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  LessonRow() {
    const upcoming = this.upcomingLesson();
    if (upcoming) {
      Row({ space: 12 }) {
        Column() {
          PotteryIcon({ size: 24, color: Theme.brandDark })
        }
        .width(48)
        .height(48)
        .borderRadius(Theme.radiusSmall)
        .backgroundColor(Theme.brandSoft)
        .justifyContent(FlexAlign.Center)
        .alignItems(HorizontalAlign.Center)

        Column({ space: 4 }) {
          Text(upcoming.courseTitle)
            .fontSize(16)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textPrimary)
          Text(`${upcoming.date} ${upcoming.timeSlot}`)
            .fontSize(13)
            .fontColor(Theme.textSecondary)
        }
        .alignItems(HorizontalAlign.Start)
        .layoutWeight(1)
      }
      .width('100%')
      .alignItems(VerticalAlign.Center)
    } else {
      Text('暂无待上课程')
        .fontSize(14)
        .fontColor(Theme.textSecondary)
    }
  }

  private currentPoints(): number {
    const m = this.ctrl.state.currentMember();
    return m ? m.points : 0;
  }

  private isEmpty(): boolean {
    return this.ctrl.state.members.length === 0 && this.ctrl.state.bookings.length === 0;
  }

  private upcomingLesson(): { courseTitle: string; date: string; timeSlot: string } | null {
    const today = DateUtil.today();
    const list = this.ctrl.state.bookings
      .filter(b => b.status === 'confirmed' && b.date >= today)
      .sort((a, b) => (a.date > b.date ? 1 : -1));
    const first = list[0];
    if (!first) return null;
    const course = this.ctrl.state.courses.find(c => c.id === first.courseId);
    return {
      courseTitle: course?.title ?? '课程',
      date: first.date,
      timeSlot: first.timeSlot,
    };
  }
}

