import { AppController, AppState, MemberUpdateInput } from '../viewmodel/AppState';
import { Theme } from '../common/Theme';
import { Member, WorkPhoto } from '../models/Models';
import { promptAction } from '@kit.ArkUI';
import { photoAccessHelper } from '@kit.MediaLibraryKit';

@Component
export struct ProfilePage {
  @ObjectLink state: AppState;
  @Prop ctrl: AppController;
  onBack: () => void = () => {};

  @State editing: boolean = false;
  @State draftName: string = '';
  @State draftPhone: string = '';
  @State draftBio: string = '';
  @State draftCrafts: string = '';

  build() {
    Column() {
      this.Header('会员档案')

      Scroll() {
        Column({ space: 16 }) {
          const m = this.state.currentMember();
          if (m) {
            Column({ space: 12 }) {
              Column() {
                Text(m.name.slice(0, 1))
                  .id('profile-avatar')
                  .fontSize(32)
                  .fontWeight(FontWeight.Bold)
                  .fontColor(Theme.textOnBrand)
              }
              .width(80)
              .height(80)
              .borderRadius(40)
              .backgroundColor(Theme.brandPrimary)
              .justifyContent(FlexAlign.Center)
              .alignItems(HorizontalAlign.Center)

              Text(m.name)
                .id('profile-name')
                .fontSize(20)
                .fontWeight(FontWeight.Bold)
                .fontColor(Theme.textPrimary)

              Text(`${this.ctrl.state.levelName(m.id)} · ${m.points} 积分`)
                .id('profile-points-level')
                .fontSize(14)
                .fontColor(Theme.textSecondary)

              if (this.editing) {
                this.EditForm()
              } else {
                this.ReadOnlyProfile(m)
              }
            }
            .width('100%')
            .padding(20)
            .borderRadius(Theme.radiusCard)
            .backgroundColor(Theme.cardBg)
          } else {
            Column({ space: 8 }) {
              Text('尚未选择会员')
                .fontSize(16)
                .fontWeight(FontWeight.Bold)
                .fontColor(Theme.textPrimary)
            }
            .width('100%')
            .padding(32)
          }
        }
        .width('100%')
        .padding(Theme.pageHorizontalPadding)
        .constraintSize({ maxWidth: Theme.contentMaxWidth })
      }
      .width('100%')
      .layoutWeight(1)
      .scrollBar(BarState.Off)
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  Header(title: string) {
    Stack({ alignContent: Alignment.Center }) {
      Column()
        .width('100%')
        .height(56)
        .linearGradient({
          angle: 180,
          direction: GradientDirection.Bottom,
          colors: [[Theme.headerGradientStart, 0.0], [Theme.headerGradientEnd, 1.0]]
        })
        .borderRadius({ bottomLeft: 28, bottomRight: 28 })

      Row() {
        Button({ type: ButtonType.Circle }) {
          Text('<')
            .fontSize(18)
            .fontColor(Theme.textOnBrand)
        }
        .id('back-button')
        .width(40)
        .height(40)
        .backgroundColor('rgba(255,255,255,0.16)')
        .onClick(() => this.onBack())
      }
      .width('100%')
      .height(56)
      .padding({ left: 16 })
      .justifyContent(FlexAlign.Start)

      Text(title)
        .fontSize(18)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textOnBrand)
    }
    .width('100%')
    .height(56)
  }

